import React, { useEffect, useState } from "react";
import { supabase } from "../supabaseClient";
import { 
    LayoutGrid, Users, Calendar, CheckCircle, 
    LogOut, Search, RefreshCcw, MoreVertical, 
    MessageCircle, MapPin, Clock, Shield
} from "lucide-react";
import "./Dashboard.css";

const Dashboard = ({ session }) => {
    const [rides, setRides] = useState([]);
    const [searchQuery, setSearchQuery] = useState("");
    const [filter, setFilter] = useState("all");
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        fetchRides();
        const channel = supabase.channel('ops-room').on('postgres_changes', { event: '*', schema: 'public', table: 'rides' }, () => fetchRides()).subscribe();
        return () => supabase.removeChannel(channel);
    }, []);

    const fetchRides = async () => {
        const { data } = await supabase.from("rides").select("*").order("created_at", { ascending: false });
        if (data) setRides(data);
        setLoading(false);
    };

    const updateStatus = async (id, status) => {
        await supabase.from('rides').update({ status }).eq('id', id);
        fetchRides();
    };

    const handleWhatsApp = (phone, name) => {
        const url = `https://wa.me/91${phone.replace(/\D/g, '')}?text=Hi ${name}, this is PAHEL Admin. Your ride is confirmed.`;
        window.open(url, '_blank');
    };

    // Stats Calculation
    const stats = {
        total: rides.length,
        pending: rides.filter(r => r.status === 'pending').length,
        today: rides.filter(r => r.ride_date === new Date().toISOString().split('T')[0]).length,
        completed: rides.filter(r => r.status === 'completed').length
    };

    // Filter & Search Logic
    const filteredRides = rides.filter(ride => {
        const matchesSearch = ride.passenger_name.toLowerCase().includes(searchQuery.toLowerCase()) || ride.phone_number.includes(searchQuery);
        const matchesFilter = filter === "all" || ride.status === filter;
        return matchesSearch && matchesFilter;
    });

    return (
        <div className="dashboard-layout">
            {/* Sidebar */}
            <aside className="sidebar">
                <div className="sidebar-logo">
                    <Shield size={28} color="#2563eb" /> PAHEL OPS
                </div>
                <div className="nav-item active"><LayoutGrid size={20} /> Overview</div>
                <div className="nav-item"><Users size={20} /> Driver Fleet</div>
                <div className="nav-item"><Calendar size={20} /> Schedules</div>
                <div style={{ marginTop: 'auto' }} className="nav-item" onClick={() => supabase.auth.signOut()}>
                    <LogOut size={20} /> Logout
                </div>
            </aside>

            {/* Main Area */}
            <main className="main-area">
                <header className="header-row">
                    <div>
                        <h2 style={{ margin: 0 }}>Operations Dashboard</h2>
                        <span style={{ color: 'var(--text-muted)', fontSize: '14px' }}>Welcome back, {session.user.email}</span>
                    </div>
                    <button className="action-icon-btn" onClick={fetchRides}><RefreshCcw size={20} /></button>
                </header>

                {/* Stats */}
                <div className="stats-grid">
                    <div className="stat-card">
                        <div className="stat-header">Total Requests <Users size={16} /></div>
                        <div className="stat-value">{stats.total}</div>
                    </div>
                    <div className="stat-card">
                        <div className="stat-header">Pending Approval <Clock size={16} /></div>
                        <div className="stat-value" style={{ color: 'var(--warning)' }}>{stats.pending}</div>
                    </div>
                    <div className="stat-card">
                        <div className="stat-header">Today's Schedule <Calendar size={16} /></div>
                        <div className="stat-value" style={{ color: 'var(--primary)' }}>{stats.today}</div>
                    </div>
                    <div className="stat-card">
                        <div className="stat-header">Trips Completed <CheckCircle size={16} /></div>
                        <div className="stat-value" style={{ color: 'var(--success)' }}>{stats.completed}</div>
                    </div>
                </div>

                {/* Table Content */}
                <div className="content-card">
                    <div className="toolbar">
                        <div style={{ display: 'flex', gap: '12px' }}>
                            <input 
                                type="text" 
                                placeholder="Search by name or phone..." 
                                className="search-input"
                                onChange={(e) => setSearchQuery(e.target.value)}
                            />
                            <select className="search-input" style={{ width: '150px' }} onChange={(e) => setFilter(e.target.value)}>
                                <option value="all">All Status</option>
                                <option value="pending">Pending</option>
                                <option value="confirmed">Confirmed</option>
                                <option value="completed">Completed</option>
                            </select>
                        </div>
                    </div>

                    <table className="modern-table">
                        <thead>
                            <tr>
                                <th>Passenger</th>
                                <th>Route</th>
                                <th>Schedule</th>
                                <th>Status</th>
                                <th>Actions</th>
                            </tr>
                        </thead>
                        <tbody>
                            {filteredRides.map(ride => (
                                <tr key={ride.id}>
                                    <td>
                                        <div style={{ fontWeight: '600' }}>{ride.passenger_name}</div>
                                        <div style={{ color: 'var(--text-muted)', fontSize: '12px', display: 'flex', alignItems: 'center', gap: '4px' }}>
                                            <Phone size={10} /> {ride.phone_number}
                                        </div>
                                    </td>
                                    <td>
                                        <div style={{ display: 'flex', alignItems: 'center', gap: '6px', fontSize: '13px' }}>
                                            <MapPin size={12} color="var(--success)" /> {ride.pickup_location}
                                        </div>
                                        <div style={{ display: 'flex', alignItems: 'center', gap: '6px', fontSize: '13px', marginTop: '4px' }}>
                                            <MapPin size={12} color="var(--danger)" /> {ride.drop_location}
                                        </div>
                                    </td>
                                    <td>
                                        <div style={{ fontWeight: '500' }}>{ride.ride_date}</div>
                                        <div style={{ fontSize: '12px', color: 'var(--text-muted)' }}>{ride.ride_time}</div>
                                    </td>
                                    <td>
                                        <span className={`status-pill status-${ride.status}`}>
                                            {ride.status}
                                        </span>
                                    </td>
                                    <td>
                                        <div style={{ display: 'flex', gap: '12px' }}>
                                            <button className="action-icon-btn" title="WhatsApp" onClick={() => handleWhatsApp(ride.phone_number, ride.passenger_name)}>
                                                <MessageCircle size={18} color="#25D366" />
                                            </button>
                                            <button className="action-icon-btn" title="Complete" onClick={() => updateStatus(ride.id, 'completed')}>
                                                <CheckCircle size={18} color="var(--success)" />
                                            </button>
                                            <button className="action-icon-btn" title="Cancel" onClick={() => updateStatus(ride.id, 'cancelled')}>
                                                <XCircle size={18} color="var(--danger)" />
                                            </button>
                                        </div>
                                    </td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                </div>
            </main>
        </div>
    );
};

// Simple Icon fallback
const XCircle = ({ size, color }) => (
    <svg width={size} height={size} viewBox="0 0 24 24" fill="none" stroke={color} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
        <circle cx="12" cy="12" r="10"/><line x1="15" y1="9" x2="9" y2="15"/><line x1="9" y1="9" x2="15" y2="15"/>
    </svg>
);

export default Dashboard;
